const { BigQuery } = require('@google-cloud/bigquery');
const { Storage } = require('@google-cloud/storage');

// Initialize clients
const bigquery = new BigQuery();
const storage = new Storage();

// Environment validation
if (!process.env.GOOGLE_CLOUD_PROJECT) {
  throw new Error('GOOGLE_CLOUD_PROJECT environment variable is required');
}

// Input validation function
function validateInput(input) {
  if (!input || typeof input !== 'object') {
    throw new Error('Invalid input: Expected object');
  }
  
  if (!input.query || typeof input.query !== 'string') {
    throw new Error('Invalid input: query is required and must be a string');
  }
  
  if (input.maxResults && (typeof input.maxResults !== 'number' || input.maxResults <= 0)) {
    throw new Error('Invalid input: maxResults must be a positive number');
  }
  
  return true;
}

// Secure query execution with parameterized inputs
async function executeSecureQuery(query, params = {}) {
  try {
    const queryOptions = {
      query: query,
      params: params,
      location: 'US',
      useQueryCache: true,
      useLegacySql: false
    };
    
    const [job] = await bigquery.createQueryJob(queryOptions);
    const [rows] = await job.getQueryResults();
    
    return rows;
  } catch (error) {
    if (error.code === 400) {
      throw new Error('Invalid query or parameters');
    }
    throw error;
  }
}

// Data aggregation function
async function aggregateData(rows) {
  const aggregation = {
    totalRecords: rows.length,
    processedAt: new Date().toISOString(),
    summary: {}
  };
  
  // Process data efficiently
  for (const row of rows) {
    for (const [key, value] of Object.entries(row)) {
      if (!aggregation.summary[key]) {
        aggregation.summary[key] = {
          count: 0,
          values: new Set()
        };
      }
      
      aggregation.summary[key].count++;
      if (typeof value === 'string' || typeof value === 'number') {
        aggregation.summary[key].values.add(value);
      }
    }
  }
  
  return aggregation;
}

